#include <stdio.h>
#include <stdlib.h>
#define MAX_BITS 32
#define MAX_NODES (1 << MAX_BITS)
// Define the Trie node structure
typedef struct TrieNode {
    struct TrieNode* children[2];
} TrieNode;
// Function to create a new Trie node
TrieNode* createTrieNode() {
    TrieNode* node = (TrieNode*)malloc(sizeof(TrieNode));
    node->children[0] = NULL;
    node->children[1] = NULL;
    return node;
}
// Function to insert a number into the Trie
void insert(TrieNode* root, int num) {
    TrieNode* node = root;
    for (int i = MAX_BITS - 1; i >= 0; i--) {
        int bit = (num >> i) & 1;
        if (node->children[bit] == NULL) {
            node->children[bit] = createTrieNode();
        }
        node = node->children[bit];
    }
}
// Function to find the maximum XOR value for a given number
int findMaxXOR(TrieNode* root, int num) {
    TrieNode* node = root;
    int max_xor = 0;
    for (int i = MAX_BITS - 1; i >= 0; i--) {
        int bit = (num >> i) & 1;
        if (node->children[1 - bit] != NULL) {
            max_xor |= (1 << i);
            node = node->children[1 - bit];
        } else {
            node = node->children[bit];
        }
    }
    return max_xor;
}
// Function to find the maximum XOR value for a given list
int max_xor(int* nums, int n) {
    TrieNode* root = createTrieNode();
    for (int i = 0; i < n; i++) {
        insert(root, nums[i]);
    }
    int max_xor = 0;
    for (int i = 0; i < n; i++) {
        int xor = findMaxXOR(root, nums[i]);
        if (xor > max_xor) {
            max_xor = xor;
        }
    }
    return max_xor;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int* nums = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &nums[i]);
        }
        int max_xor = max_xor(nums, n);
        printf("%d\n", max_xor);
        free(nums);
    }
    return 0;
}

