import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;
public class Main {
    // Define the Trie node structure
    static class TrieNode {
        Map<Integer, TrieNode> children = new HashMap<>();
    }
    // Function to create a new Trie node
    static TrieNode createTrieNode() {
        return new TrieNode();
    }
    // Function to insert a number into the Trie
    static void insert(TrieNode root, int num) {
        TrieNode node = root;
        for (int i = 31; i >= 0; i--) {
            int bit = (num >> i) & 1;
            if (!node.children.containsKey(bit)) {
                node.children.put(bit, createTrieNode());
            }
            node = node.children.get(bit);
        }
    }
    // Function to find the maximum XOR value for a given number
    static int findMaxXOR(TrieNode root, int num) {
        TrieNode node = root;
        int max_xor = 0;
        for (int i = 31; i >= 0; i--) {
            int bit = (num >> i) & 1;
            if (node.children.containsKey(1 - bit)) {
                max_xor |= (1 << i);
                node = node.children.get(1 - bit);
            } else {
                node = node.children.get(bit);
            }
        }
        return max_xor;
    }
    // Function to find the maximum XOR value for a given list
    static int max_xor(int[] nums) {
        TrieNode root = createTrieNode();
        for (int num : nums) {
            insert(root, num);
        }
        int max_xor = 0;
        for (int num : nums) {
            int xor = findMaxXOR(root, num);
            if (xor > max_xor) {
                max_xor = xor;
            }
        }
        return max_xor;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int[] nums = new int[n];
            for (int i = 0; i < n; i++) {
                nums[i] = scanner.nextInt();
            }
            int max_xor = max_xor(nums);
            System.out.println(max_xor);
        }
    }
}

